import{_ as t}from"./chunks/abstract.Cq9_B8qJ.js";import{_ as r,o,c as s,ae as a}from"./chunks/framework.U1Gow_7P.js";const f=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md"}'),n={name:"guide/index.md"};function i(c,e,l,p,d,u){return o(),s("div",null,e[0]||(e[0]=[a('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>LinkSocks is a secure SOCKS5 proxy over WebSocket. It allows you to traverse firewalls and complex network topologies by tunneling traffic through standard web connections.</p><p>Its architecture allows you to hide the proxy server behind a WAF or CDN (like Cloudflare). By disguising proxy traffic as normal HTTPS requests, it protects the server&#39;s real IP address and evades deep packet inspection.</p><p>Crucially, it supports Serverless Intranet Penetration (compatible with Cloudflare Workers). This allows you to bridge two private networks securely without a dedicated VPS. Since both the user and the internal resource actively connect to the serverless cloud relay, you can access your home or office network without a public IP or opening any risky inbound ports.</p><p><img src="'+t+'" alt="Architecture"></p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>LinkSocks enables two main proxy scenarios:</p><p><strong>Forward Proxy</strong>: Client connects to server&#39;s network through SOCKS5. Server acts as gateway to internet.</p><p><strong>Reverse Proxy</strong>: Server exposes SOCKS5 interface, multiple clients share their network access with load balancing.</p><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><p><strong>CAPTCHA Solving</strong>: Use client IPs instead of server IP to bypass Cloudflare restrictions</p><p><strong>Network Pivoting</strong>: Access internal networks through compromised hosts without exposing attack infrastructure</p><p><strong>Traffic Disguise</strong>: WebSocket transport appears as normal web traffic, bypassing firewall restrictions</p>',13)]))}const w=r(n,[["render",i]]);export{f as __pageData,w as default};
